import { dataValidationService } from "./DataValidationService";

export async function fetchValidationFields( type) {
    let response = await dataValidationService.fetchValidationFields( type);
    return response ;
}

export async function saveValidationFields( validations,attributeId,attributeValidationId) {
    let response = await dataValidationService.saveValidationFields(validations,attributeId,attributeValidationId);
    return response ;
}

export async function fetchRegexGuide() {
    let response = await dataValidationService.fetchRegexGuide();
    return response ;
}


export async function fetchValidationRule() {
    let response = await dataValidationService.fetchValidationRule();
    return response ;
}

export async function saveValidationRule( dataValidationRequestDto) {
    let response = await dataValidationService.saveValidationRule(dataValidationRequestDto);
    return response ;
}

export async function deleteValidationRule( ruleId ) {
    let response = await dataValidationService.deleteValidationRule(ruleId);
    return response ;
}
